"use client";

import {
  forwardRef,
  type HTMLAttributes,
  type MouseEvent,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { cn } from "../lib/cn.js";

/** One entry in the table of contents, linking to a heading by its `id`. */
export interface TableOfContentsItem {
  /** The `id` of the heading element this entry links to. */
  id: string;
  /** Visible link text. */
  label: string;
  /**
   * Nesting level, `0`-based — each level indents the link one step further.
   * Defaults to `0`.
   */
  depth?: number;
}

export interface TableOfContentsProps extends Omit<HTMLAttributes<HTMLElement>, "children"> {
  /**
   * The entries to render, in document order. When omitted, headings are
   * auto-discovered from the DOM via {@link TableOfContentsProps.selector}.
   */
  items?: TableOfContentsItem[];
  /**
   * CSS selector used to auto-discover headings when
   * {@link TableOfContentsProps.items} is omitted. Only elements with an `id`
   * participate; depth is derived from the heading level (the shallowest level
   * found becomes depth 0). Defaults to `"h2, h3"`.
   */
  selector?: string;
  /**
   * `id` of the element that scopes heading discovery. When that element is
   * itself a scroll container (`overflow-y: auto | scroll`), it also becomes
   * the scrollspy root and the target of click-to-scroll — otherwise the
   * window scrolls. Defaults to the whole document.
   */
  containerId?: string;
  /**
   * Pixels between the top of the scroll root and the activation line — match
   * your sticky-header height. Also subtracted when scrolling to a section on
   * click. Defaults to `0`.
   */
  offset?: number;
}

const DEFAULT_SELECTOR = "h2, h3";
/** Separator for the joined-ids effect key — cannot appear in an HTML `id`. */
const ID_SEPARATOR = "�";
/** Indent applied per depth level, in rem (plus the same amount as a base). */
const INDENT_STEP_REM = 0.75;
const MAX_DEPTH = 5;

const prefersReducedMotion = (): boolean =>
  typeof window !== "undefined" &&
  typeof window.matchMedia === "function" &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

function clampDepth(depth: number | undefined): number {
  if (depth === undefined || !Number.isFinite(depth)) return 0;
  return Math.min(Math.max(Math.round(depth), 0), MAX_DEPTH);
}

/**
 * Resolve the scroll container for `containerId`, or `null` when the id is
 * absent, unknown, or the element does not actually scroll — in which case
 * both the observer root and click-to-scroll fall back to the window.
 */
function resolveScrollParent(containerId: string | undefined): HTMLElement | null {
  if (!containerId) return null;
  const container = document.getElementById(containerId);
  if (!container) return null;
  const { overflowY } = getComputedStyle(container);
  return overflowY === "auto" || overflowY === "scroll" ? container : null;
}

/**
 * A scrollspy "On this page" table of contents. Section headings are watched by
 * a single `IntersectionObserver` whose root margin carves an activation band
 * across the top quarter of the scroll root (the window, or the scrollable
 * container named by `containerId`): the first observed heading inside the band
 * is the active section, and when the band is empty — e.g. deep inside a long
 * section body — the heading that last crossed above it stays active. Scroll
 * position is never polled and no scroll listener is attached; React re-renders
 * only when the active section actually changes.
 *
 * The active link gains `text-fg` + `aria-current="location"`, and a small
 * indicator bar translates vertically to the active row — its `transform` /
 * `height` are written straight to the DOM and animated by a CSS transition
 * (`motion-reduce:transition-none`, so opted-out visitors get an instant cut).
 * Clicking a link smooth-scrolls to its heading (instant under
 * `prefers-reduced-motion`) and rewrites the URL hash without pushing a history
 * entry per click.
 *
 * Entries come from {@link TableOfContentsProps.items}, or are auto-discovered
 * once on mount from the headings matching {@link TableOfContentsProps.selector}
 * — headings need an `id` to participate.
 */
export const TableOfContents = forwardRef<HTMLElement, TableOfContentsProps>(
  (
    {
      items,
      selector = DEFAULT_SELECTOR,
      containerId,
      offset = 0,
      className,
      "aria-label": ariaLabel = "On this page",
      ...props
    },
    ref,
  ) => {
    const navRef = useRef<HTMLElement | null>(null);
    const indicatorRef = useRef<HTMLSpanElement | null>(null);

    const setNavRef = useCallback(
      (node: HTMLElement | null) => {
        navRef.current = node;
        if (typeof ref === "function") {
          ref(node);
        } else if (ref) {
          ref.current = node;
        }
      },
      [ref],
    );

    // Auto-discovery runs in an effect (never during render), so SSR output is
    // a stable empty list and the hydrated markup matches — no mismatches.
    const [discovered, setDiscovered] = useState<TableOfContentsItem[]>([]);
    const resolvedItems = items ?? discovered;

    useEffect(() => {
      if (items) return;
      const scope: ParentNode | null = containerId
        ? document.getElementById(containerId)
        : document;
      if (!scope) return;
      const headings = Array.from(scope.querySelectorAll<HTMLElement>(selector)).filter(
        (element) => element.id.length > 0,
      );
      if (headings.length === 0) {
        setDiscovered([]);
        return;
      }
      // Depth is relative to the shallowest heading found, so "h2, h3" yields
      // depths 0/1 regardless of where the page's outline starts.
      const levels = headings.map((element) => {
        const match = /^H([1-6])$/.exec(element.tagName);
        return match ? Number(match[1]) : null;
      });
      const minLevel = Math.min(...levels.filter((level): level is number => level !== null));
      setDiscovered(
        headings.map((element, index) => {
          const level = levels[index];
          return {
            id: element.id,
            label: element.textContent?.trim() || element.id,
            depth: typeof level === "number" ? level - minLevel : 0,
          };
        }),
      );
    }, [items, selector, containerId]);

    // Keyed on the joined ids (not the array identity) so an inline `items`
    // literal does not tear the observer down on every render.
    const idsKey = resolvedItems.map((item) => item.id).join(ID_SEPARATOR);

    const [activeId, setActiveId] = useState<string | null>(null);

    useEffect(() => {
      const orderedIds = idsKey.length > 0 ? idsKey.split(ID_SEPARATOR) : [];
      if (orderedIds.length === 0 || typeof IntersectionObserver === "undefined") return;
      const targets = orderedIds
        .map((id) => document.getElementById(id))
        .filter((element): element is HTMLElement => element !== null);
      if (targets.length === 0) return;

      const root = resolveScrollParent(containerId);
      const inBand = new Set<string>();

      const observer = new IntersectionObserver(
        (entries) => {
          for (const entry of entries) {
            if (entry.isIntersecting) {
              inBand.add(entry.target.id);
            } else {
              inBand.delete(entry.target.id);
            }
          }
          // The topmost heading inside the activation band wins — correct for
          // both scroll directions since the band sits at the top of the root.
          const first = orderedIds.find((id) => inBand.has(id));
          if (first !== undefined) {
            setActiveId(first);
            return;
          }
          // Band is empty (a long section body fills the viewport): the
          // section whose heading last crossed above the band is still the one
          // being read. This scan only runs on band-emptying transitions.
          const bandTop = (root ? root.getBoundingClientRect().top : 0) + offset;
          let current: string | null = null;
          for (const target of targets) {
            if (target.getBoundingClientRect().top <= bandTop + 1) current = target.id;
          }
          setActiveId(current ?? orderedIds[0] ?? null);
        },
        // Activation band: from `offset` below the root's top edge down to 25%
        // of its height. Headings report only when they cross these lines, so
        // the callback fires far less often than a scroll listener would.
        { root, rootMargin: `${-offset}px 0px -75% 0px`, threshold: 0 },
      );

      for (const target of targets) observer.observe(target);
      return () => observer.disconnect();
    }, [idsKey, containerId, offset]);

    // Slide the indicator bar to the active row. Height + translateY are
    // written straight to the DOM (no extra render) and animated by the CSS
    // transition on the element; a ResizeObserver keeps it pinned when the nav
    // reflows (font load, container resize).
    // biome-ignore lint/correctness/useExhaustiveDependencies: activeId/idsKey are the re-measure triggers; the DOM reads happen at effect time.
    useLayoutEffect(() => {
      const nav = navRef.current;
      const indicator = indicatorRef.current;
      if (!nav || !indicator) return;

      const position = () => {
        const active = nav.querySelector<HTMLElement>('a[data-active="true"]');
        if (!active) {
          indicator.style.opacity = "0";
          return;
        }
        const navRect = nav.getBoundingClientRect();
        const linkRect = active.getBoundingClientRect();
        indicator.style.opacity = "1";
        indicator.style.height = `${linkRect.height}px`;
        indicator.style.transform = `translateY(${linkRect.top - navRect.top}px)`;
      };
      position();

      if (typeof ResizeObserver === "undefined") return;
      const observer = new ResizeObserver(position);
      observer.observe(nav);
      return () => observer.disconnect();
    }, [activeId, idsKey]);

    const handleLinkClick = useCallback(
      (event: MouseEvent<HTMLAnchorElement>, id: string) => {
        if (event.defaultPrevented) return;
        // Preserve native open-in-new-tab / window affordances.
        if (event.button !== 0 || event.metaKey || event.ctrlKey || event.shiftKey || event.altKey)
          return;
        const target = document.getElementById(id);
        if (!target) return;
        event.preventDefault();
        // Activate optimistically so the indicator answers the click at once,
        // instead of trailing the smooth scroll.
        setActiveId(id);

        const behavior: ScrollBehavior = prefersReducedMotion() ? "auto" : "smooth";
        const scroller = resolveScrollParent(containerId);
        if (scroller) {
          const top =
            target.getBoundingClientRect().top -
            scroller.getBoundingClientRect().top +
            scroller.scrollTop -
            offset;
          scroller.scrollTo({ top, behavior });
        } else {
          const top = target.getBoundingClientRect().top + window.scrollY - offset;
          window.scrollTo({ top, behavior });
        }
        // Keep the URL shareable without spamming history with one entry per click.
        window.history.replaceState(window.history.state, "", `#${id}`);
      },
      [containerId, offset],
    );

    return (
      <nav
        ref={setNavRef}
        data-slot="table-of-contents"
        aria-label={ariaLabel}
        className={cn("relative text-sm", className)}
        {...props}
      >
        <span
          ref={indicatorRef}
          aria-hidden="true"
          data-slot="table-of-contents-indicator"
          className={cn(
            "absolute start-0 top-0 w-0.5 rounded-full bg-primary opacity-0",
            "transition-[transform,height,opacity] duration-300 ease-out motion-reduce:transition-none",
          )}
        />
        <ul data-slot="table-of-contents-list" className="border-s border-border">
          {resolvedItems.map((item) => {
            const depth = clampDepth(item.depth);
            const isActive = item.id === activeId;
            return (
              <li key={item.id}>
                <a
                  href={`#${item.id}`}
                  data-slot="table-of-contents-link"
                  data-depth={depth}
                  data-active={isActive ? "true" : undefined}
                  aria-current={isActive ? "location" : undefined}
                  onClick={(event) => handleLinkClick(event, item.id)}
                  style={{ paddingInlineStart: `${(depth + 1) * INDENT_STEP_REM}rem` }}
                  className={cn(
                    "block rounded-e-md py-1.5 pe-3 leading-snug text-fg-tertiary transition-colors duration-200",
                    "hover:text-fg-secondary",
                    "outline-none focus-visible:ring-2 focus-visible:ring-ring",
                    isActive && "font-medium text-fg hover:text-fg",
                  )}
                >
                  {item.label}
                </a>
              </li>
            );
          })}
        </ul>
      </nav>
    );
  },
);
TableOfContents.displayName = "TableOfContents";
